@Composable
private fun profileErrorMessage(code: String?): String? {
    return when (code) {
        "PROFILE_NAME_EMPTY" -> stringResource(R.string.profile_error_name_empty)
        "PROFILE_EMAIL_INVALID" -> stringResource(R.string.profile_error_email_invalid)
        else -> null
    }
